public static boolean solve(long n) {
    long digitSum = 0;
    long digitProduct = 1;
    long temp = n;

    while (temp > 0) {
        long digit = temp % 10;
        digitSum += digit;
        digitProduct *= digit;
        temp /= 10;
    }

    return (digitSum + digitProduct) % n == 0;
}
